```

### 3. **Plugin SDK Core API** (`src/plugin-sdk/core.ts`)

**Key Functions Exported:**

#### `defineChannelPluginEntry(options)`
```typescript
type DefineChannelPluginEntryOptions<TPlugin = ChannelPlugin> = {
  id: string;
  name: string;
  description: string;
  plugin: TPlugin;
  configSchema?: OpenClawPluginConfigSchema | (() => OpenClawPluginConfigSchema);
  setRuntime?: (runtime: PluginRuntime) => void;
  registerCliMetadata?: (api: OpenClawPluginApi) => void;
  registerFull?: (api: OpenClawPluginApi) => void;
};
```

**Returns:**
```typescript
type DefinedChannelPluginEntry<TPlugin> = {
  id: string;
  name: string;
  description: string;
  configSchema: OpenClawPluginConfigSchema;
  register: (api: OpenClawPluginApi) => void;
  channelPlugin: TPlugin;
  setChannelRuntime?: (runtime: PluginRuntime) => void;
};
```

#### `defineSetupPluginEntry(plugin)`
Minimal helper - just returns `{ plugin }` for setup-only entries.

#### `createChatChannelPlugin<TResolvedAccount, Probe, Audit>(params)`
High-level builder for chat-style channels:

```typescript
params: {
  base: ChatChannelPluginBase<TResolvedAccount, Probe, Audit>;
  security?: ChannelSecurityAdapter<TResolvedAccount> | ChatChannelSecurityOptions<TResolvedAccount>;
  pairing?: ChannelPairingAdapter | ChatChannelPairingOptions;
  threading?: ChannelThreadingAdapter | ChatChannelThreadingOptions<TResolvedAccount>;
  outbound?: ChannelOutboundAdapter | ChatChannelAttachedOutboundOptions;
}
```

#### `createChannelPluginBase<TResolvedAccount>(params)`
Mid-level builder for optional overrides:

```typescript
params: {
  id: ChannelPlugin["id"];
  meta?: Partial<ChannelMeta>;
  setupWizard?: ChannelSetupWizard;
  capabilities?: ChannelCapabilities;
  agentPrompt?: ChannelAgentPromptAdapter;
  streaming?: ChannelStreamingAdapter;
  reload?: { configPrefixes: string[] };
  gatewayMethods?: string[];
  configSchema?: ChannelConfigSchema;
  config?: ChannelConfigAdapter<TResolvedAccount>;
  security?: ChannelSecurityAdapter<TResolvedAccount>;
  setup: ChannelSetupAdapter;  // Required
  groups?: ChannelGroupAdapter;
}
```

#### `buildChannelOutboundSessionRoute(params)`
Build canonical outbound session route:
```typescript
params: {
  cfg: OpenClawConfig;
  agentId: string;
  channel: string;
  accountId?: string | null;
  peer: { kind: "direct" | "group" | "channel"; id: string };
  chatType: "direct" | "group" | "channel";
  from: string;
  to: string;
  threadId?: string | number;
}
```

---

### 4. **Runtime Store** (`src/plugin-sdk/runtime-store.ts`)

#### `createPluginRuntimeStore<T>(errorMessage: string)`
Creates a tiny mutable runtime slot:

```typescript
type PluginRuntimeStore<T> = {
  setRuntime: (next: T) => void;
  clearRuntime: () => void;
  tryGetRuntime: () => T | null;
  getRuntime: () => T;  // Throws if not initialized
};
```

**Example from Telegram:**
```typescript
const {
  setRuntime: setTelegramRuntime,
  clearRuntime: clearTelegramRuntime,
  getRuntime: getTelegramRuntime,
} = createPluginRuntimeStore<TelegramRuntime>("Telegram runtime not initialized");
```

---

### 5. **Complete ChannelPlugin Interface** (`src/channels/plugins/types.plugin.ts`)

```typescript
type ChannelPlugin<ResolvedAccount = any, Probe = unknown, Audit = unknown> = {
  // Identity
  id: ChannelId;
  meta: ChannelMeta;

  // Static declarations
  capabilities: ChannelCapabilities;
  defaults?: { queue?: { debounceMs?: number } };
  reload?: { configPrefixes: string[]; noopPrefixes?: string[] };

  // Setup & Configuration
  setupWizard?: ChannelSetupWizard | ChannelSetupWizardAdapter;
  config: ChannelConfigAdapter<ResolvedAccount>;
  configSchema?: ChannelConfigSchema;
  setup?: ChannelSetupAdapter;

  // Security & Access Control
  pairing?: ChannelPairingAdapter;
  security?: ChannelSecurityAdapter<ResolvedAccount>;
  groups?: ChannelGroupAdapter;
  allowlist?: ChannelAllowlistAdapter;

  // Message Handling
  mentions?: ChannelMentionAdapter;
  outbound?: ChannelOutboundAdapter;
  messaging?: ChannelMessagingAdapter;
  threading?: ChannelThreadingAdapter;
  actions?: ChannelMessageActionAdapter;

  // Agent Integration
  agentPrompt?: ChannelAgentPromptAdapter;
  agentTools?: ChannelAgentToolFactory | ChannelAgentTool[];

  // Status & Monitoring
  status?: ChannelStatusAdapter<ResolvedAccount, Probe, Audit>;
  heartbeat?: ChannelHeartbeatAdapter;

  // Runtime Integration
  gatewayMethods?: string[];
  gateway?: ChannelGatewayAdapter<ResolvedAccount>;
  auth?: ChannelAuthAdapter;

  // Advanced Features
  approvalCapability?: ChannelApprovalCapability;
  elevated?: ChannelElevatedAdapter;
  commands?: ChannelCommandAdapter;
  lifecycle?: ChannelLifecycleAdapter;
  approvals?: ChannelApprovalAdapter;
  bindings?: ChannelConfiguredBindingProvider;
  conversationBindings?: ChannelConversationBindingSupport;
  streaming?: ChannelStreamingAdapter;
  directory?: ChannelDirectoryAdapter;
  resolver?: ChannelResolverAdapter;
};
```

---

### 6. **Key Adapter Shapes** (`src/channels/plugins/types.adapters.ts`)

#### ChannelSetupAdapter
```typescript
type ChannelSetupAdapter = {
  resolveAccountId?: (params: { cfg, accountId?, input? }) => string;
  resolveBindingAccountId?: (params: { cfg, agentId, accountId? }) => string | undefined;
  applyAccountName?: (params: { cfg, accountId, name? }) => OpenClawConfig;
  applyAccountConfig: (params: { cfg, accountId, input }) => OpenClawConfig;  // Required
  afterAccountConfigWritten?: (params: { previousCfg, cfg, accountId, input, runtime }) => Promise<void>;
  validateInput?: (params: { cfg, accountId, input }) => string | null;
};
```

#### ChannelConfigAdapter
```typescript
type ChannelConfigAdapter<ResolvedAccount> = {
  listAccountIds: (cfg) => string[];  // Required
  resolveAccount: (cfg, accountId?) => ResolvedAccount;  // Required
  inspectAccount?: (cfg, accountId?) => unknown;
  defaultAccountId?: (cfg) => string;
  setAccountEnabled?: (params: { cfg, accountId, enabled }) => OpenClawConfig;
  deleteAccount?: (params: { cfg, accountId }) => OpenClawConfig;
  isEnabled?: (account, cfg) => boolean;
  disabledReason?: (account, cfg) => string;
  isConfigured?: (account, cfg) => boolean | Promise<boolean>;
  unconfiguredReason?: (account, cfg) => string;
  describeAccount?: (account, cfg) => ChannelAccountSnapshot;
  resolveAllowFrom?: (params: { cfg, accountId? }) => Array<string | number>;
  formatAllowFrom?: (params: { cfg, accountId?, allowFrom }) => string[];
  resolveDefaultTo?: (params: { cfg, accountId? }) => string;
};
```

#### ChannelOutboundAdapter
```typescript
