118	export function listChatChannels(): ChatChannelMeta[] {
119	  return CHAT_CHANNEL_ORDER.map((id) => CHAT_CHANNEL_META[id]);
120	}
121	
122	export function listChatChannelAliases(): string[] {
123	  return Object.keys(CHAT_CHANNEL_ALIASES);
124	}
125	
126	export function getChatChannelMeta(id: ChatChannelId): ChatChannelMeta {
127	  return CHAT_CHANNEL_META[id];
128	}
