import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  // getChatChannelMeta is part of the channel plugin SDK pattern; "pulseboard"
  // is not yet a registered ChatChannelId so the meta is defined as a direct
  // object literal below rather than by calling getChatChannelMeta("pulseboard").
  getChatChannelMeta as _getChatChannelMeta,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/core";

type ResolvedPulseBoardAccount = {
  accountId: string;
  boardUrl: string;
  apiToken: string;
  username: string;
  configured: boolean;
};

function resolvePulseBoardAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  // Stub: resolve account from config channels.pulseboard.accounts
  const channels = (cfg.channels ?? {}) as Record<string, unknown>;
  const pbConfig = (channels.pulseboard ?? {}) as Record<string, unknown>;
  const accounts = (pbConfig.accounts ?? {}) as Record<string, unknown>;
  const aid = accountId ?? "default";
  const raw = (accounts[aid] ?? {}) as Record<string, unknown>;
  return {
    accountId: aid,
    boardUrl: typeof raw.boardUrl === "string" ? raw.boardUrl : "",
    apiToken: typeof raw.apiToken === "string" ? raw.apiToken : "",
    username: typeof raw.username === "string" ? raw.username : "",
    configured: typeof raw.boardUrl === "string" && raw.boardUrl.length > 0,
  };
}

function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const channels = (cfg.channels ?? {}) as Record<string, unknown>;
  const pbConfig = (channels.pulseboard ?? {}) as Record<string, unknown>;
  const accounts = (pbConfig.accounts ?? {}) as Record<string, unknown>;
  return Object.keys(accounts);
}

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging via boards and direct messages.",
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: listPulseBoardAccountIds,
      resolveAccount: resolvePulseBoardAccount,
      isConfigured: (account) => account.configured,
    },
    setup: {
      applyAccountConfig: ({ cfg }) => cfg,
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;
        ctx.log?.info(
          `[${account.accountId}] connecting to PulseBoard at ${account.boardUrl}`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to, accountId }) => {
      const aid = accountId ?? "default";
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pulseboard-${aid}-${Date.now()}`,
      });
    },
  },
});

